// The ensures of this synthetic det fn has the shape
//     (big_conj_about_post1_and_post2) ==> det_block_running_thread_equal(...)
// so the per-state ensures conjuncts are NOT free hypotheses in the body —
// that's why the previous attempt's bare `assert forall ...` blocks failed.
// We introduce the antecedent ourselves with an outer `if (full antecedent) { ... }`:
// inside the branch every conjunct becomes a hypothesis, and outside the `if`
// the desired implication is restored.

let target_e: EndpointPtr =
    pre_self_.get_thread(thread_ptr).endpoint_descriptors@[endpoint_index as int].unwrap();

if ({
    &&& (post1_self_.wf())
    &&& (post1_self_.page_closure() =~= pre_self_.page_closure())
    &&& (post1_self_.proc_dom() =~= pre_self_.proc_dom())
    &&& (post1_self_.endpoint_dom() == pre_self_.endpoint_dom())
    &&& (post1_self_.container_dom() == pre_self_.container_dom())
    &&& (post1_self_.thread_dom() == pre_self_.thread_dom())
    &&& (forall|p_ptr: ProcPtr|
        #![trigger post1_self_.get_proc(p_ptr)]
        pre_self_.proc_dom().contains(p_ptr) ==> post1_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr))
    &&& (forall|container_ptr: ContainerPtr|
        #![trigger post1_self_.get_container(container_ptr)]
        pre_self_.container_dom().contains(container_ptr)
        ==>
        post1_self_.get_container(container_ptr) =~= pre_self_.get_container(container_ptr))
    &&& (forall|t_ptr: ThreadPtr|
        #![trigger pre_self_.get_thread(t_ptr)]
        pre_self_.thread_dom().contains(t_ptr) && t_ptr != thread_ptr
        ==>
        pre_self_.get_thread(t_ptr) =~= post1_self_.get_thread(t_ptr))
    &&& (forall|e_ptr: EndpointPtr|
        #![trigger post1_self_.get_endpoint(e_ptr)]
        post1_self_.endpoint_dom().contains(e_ptr)
        &&
        e_ptr != pre_self_.get_thread(thread_ptr).endpoint_descriptors@[endpoint_index as int].unwrap()
        ==> pre_self_.get_endpoint(e_ptr) =~= post1_self_.get_endpoint(e_ptr))
    &&& (post1_self_.get_thread(thread_ptr).endpoint_descriptors
        =~= pre_self_.get_thread(thread_ptr).endpoint_descriptors)
    &&& (post1_self_.get_thread(thread_ptr).ipc_payload =~= ipc_payload)
    &&& (post1_self_.get_thread(thread_ptr).state == ThreadState::BLOCKED)
    &&& (post1_self_.get_endpoint(
        pre_self_.get_thread(
            thread_ptr,
        ).endpoint_descriptors@[endpoint_index as int].unwrap(),
    ).queue_state == pre_self_.get_endpoint(
        pre_self_.get_thread(
            thread_ptr,
        ).endpoint_descriptors@[endpoint_index as int].unwrap(),
    ).queue_state)
    &&& (post1_self_.get_endpoint(
        pre_self_.get_thread(
            thread_ptr,
        ).endpoint_descriptors@[endpoint_index as int].unwrap(),
    ).owning_threads == pre_self_.get_endpoint(
        pre_self_.get_thread(
            thread_ptr,
        ).endpoint_descriptors@[endpoint_index as int].unwrap(),
    ).owning_threads)
    &&& (post1_self_.get_endpoint(
        pre_self_.get_thread(
            thread_ptr,
        ).endpoint_descriptors@[endpoint_index as int].unwrap(),
    ).queue@ == pre_self_.get_endpoint(
        pre_self_.get_thread(
            thread_ptr,
        ).endpoint_descriptors@[endpoint_index as int].unwrap(),
    ).queue@.push(thread_ptr))
    &&& (post2_self_.wf())
    &&& (post2_self_.page_closure() =~= pre_self_.page_closure())
    &&& (post2_self_.proc_dom() =~= pre_self_.proc_dom())
    &&& (post2_self_.endpoint_dom() == pre_self_.endpoint_dom())
    &&& (post2_self_.container_dom() == pre_self_.container_dom())
    &&& (post2_self_.thread_dom() == pre_self_.thread_dom())
    &&& (forall|p_ptr: ProcPtr|
        #![trigger post2_self_.get_proc(p_ptr)]
        pre_self_.proc_dom().contains(p_ptr) ==> post2_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr))
    &&& (forall|container_ptr: ContainerPtr|
        #![trigger post2_self_.get_container(container_ptr)]
        pre_self_.container_dom().contains(container_ptr)
        ==>
        post2_self_.get_container(container_ptr) =~= pre_self_.get_container(container_ptr))
    &&& (forall|t_ptr: ThreadPtr|
        #![trigger pre_self_.get_thread(t_ptr)]
        pre_self_.thread_dom().contains(t_ptr) && t_ptr != thread_ptr
        ==>
        pre_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr))
    &&& (forall|e_ptr: EndpointPtr|
        #![trigger post2_self_.get_endpoint(e_ptr)]
        post2_self_.endpoint_dom().contains(e_ptr)
        &&
        e_ptr != pre_self_.get_thread(thread_ptr).endpoint_descriptors@[endpoint_index as int].unwrap()
        ==> pre_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr))
    &&& (post2_self_.get_thread(thread_ptr).endpoint_descriptors
        =~= pre_self_.get_thread(thread_ptr).endpoint_descriptors)
    &&& (post2_self_.get_thread(thread_ptr).ipc_payload =~= ipc_payload)
    &&& (post2_self_.get_thread(thread_ptr).state == ThreadState::BLOCKED)
    &&& (post2_self_.get_endpoint(
        pre_self_.get_thread(
            thread_ptr,
        ).endpoint_descriptors@[endpoint_index as int].unwrap(),
    ).queue_state == pre_self_.get_endpoint(
        pre_self_.get_thread(
            thread_ptr,
        ).endpoint_descriptors@[endpoint_index as int].unwrap(),
    ).queue_state)
    &&& (post2_self_.get_endpoint(
        pre_self_.get_thread(
            thread_ptr,
        ).endpoint_descriptors@[endpoint_index as int].unwrap(),
    ).owning_threads == pre_self_.get_endpoint(
        pre_self_.get_thread(
            thread_ptr,
        ).endpoint_descriptors@[endpoint_index as int].unwrap(),
    ).owning_threads)
    &&& (post2_self_.get_endpoint(
        pre_self_.get_thread(
            thread_ptr,
        ).endpoint_descriptors@[endpoint_index as int].unwrap(),
    ).queue@ == pre_self_.get_endpoint(
        pre_self_.get_thread(
            thread_ptr,
        ).endpoint_descriptors@[endpoint_index as int].unwrap(),
    ).queue@.push(thread_ptr))
}) {
    // Domains agree across the two post-states by chaining through pre_self_.
    assert(post1_self_.container_dom() == post2_self_.container_dom());
    assert(post1_self_.proc_dom() =~= post2_self_.proc_dom());
    assert(post1_self_.thread_dom() == post2_self_.thread_dom());
    assert(post1_self_.endpoint_dom() == post2_self_.endpoint_dom());

    // Domain equalities at the underlying perm-map level.
    assert((post1_self_.container_perms)@.dom() =~= (post2_self_.container_perms)@.dom());
    assert((post1_self_.process_perms)@.dom() =~= (post2_self_.process_perms)@.dom());
    assert((post1_self_.thread_perms)@.dom() =~= (post2_self_.thread_perms)@.dom());
    assert((post1_self_.endpoint_perms)@.dom() =~= (post2_self_.endpoint_perms)@.dom());

    // Procs: pointwise equality between the two posts via pre_self_.
    assert forall|p_ptr: ProcPtr|
        #![trigger post1_self_.get_proc(p_ptr), post2_self_.get_proc(p_ptr)]
        pre_self_.proc_dom().contains(p_ptr) implies
        post1_self_.get_proc(p_ptr) =~= post2_self_.get_proc(p_ptr) by {
        assert(post1_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
        assert(post2_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
    }

    // Containers: pointwise equality.
    assert forall|c_ptr: ContainerPtr|
        #![trigger post1_self_.get_container(c_ptr), post2_self_.get_container(c_ptr)]
        pre_self_.container_dom().contains(c_ptr) implies
        post1_self_.get_container(c_ptr) =~= post2_self_.get_container(c_ptr) by {
        assert(post1_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
        assert(post2_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
    }

    // Non-target threads: pointwise equality. Both ensures share the trigger
    // `pre_self_.get_thread(t_ptr)`, so naming it once fires both.
    assert forall|t_ptr: ThreadPtr|
        #![trigger pre_self_.get_thread(t_ptr)]
        pre_self_.thread_dom().contains(t_ptr) && t_ptr != thread_ptr implies
        post1_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr) by {
        assert(pre_self_.get_thread(t_ptr) =~= post1_self_.get_thread(t_ptr));
        assert(pre_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr));
    }

    // Non-target endpoints: pointwise equality. Trigger pattern uses both posts'
    // get_endpoint so each ensures clause is instantiated together.
    assert forall|e_ptr: EndpointPtr|
        #![trigger post1_self_.get_endpoint(e_ptr), post2_self_.get_endpoint(e_ptr)]
        pre_self_.endpoint_dom().contains(e_ptr) && e_ptr != target_e implies
        post1_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr) by {
        assert(post1_self_.endpoint_dom().contains(e_ptr));
        assert(post2_self_.endpoint_dom().contains(e_ptr));
        assert(pre_self_.get_endpoint(e_ptr) =~= post1_self_.get_endpoint(e_ptr));
        assert(pre_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr));
    }

    // Pinned fields of the target thread agree between the two runs.
    assert(post1_self_.get_thread(thread_ptr).endpoint_descriptors
        =~= pre_self_.get_thread(thread_ptr).endpoint_descriptors);
    assert(post2_self_.get_thread(thread_ptr).endpoint_descriptors
        =~= pre_self_.get_thread(thread_ptr).endpoint_descriptors);
    assert(post1_self_.get_thread(thread_ptr).endpoint_descriptors
        =~= post2_self_.get_thread(thread_ptr).endpoint_descriptors);

    assert(post1_self_.get_thread(thread_ptr).ipc_payload =~= ipc_payload);
    assert(post2_self_.get_thread(thread_ptr).ipc_payload =~= ipc_payload);
    assert(post1_self_.get_thread(thread_ptr).ipc_payload
        =~= post2_self_.get_thread(thread_ptr).ipc_payload);

    assert(post1_self_.get_thread(thread_ptr).state == ThreadState::BLOCKED);
    assert(post2_self_.get_thread(thread_ptr).state == ThreadState::BLOCKED);
    assert(post1_self_.get_thread(thread_ptr).state
        == post2_self_.get_thread(thread_ptr).state);

    // Pinned fields of the target endpoint agree between the two runs.
    assert(post1_self_.get_endpoint(target_e).queue_state
        == pre_self_.get_endpoint(target_e).queue_state);
    assert(post2_self_.get_endpoint(target_e).queue_state
        == pre_self_.get_endpoint(target_e).queue_state);
    assert(post1_self_.get_endpoint(target_e).queue_state
        == post2_self_.get_endpoint(target_e).queue_state);

    assert(post1_self_.get_endpoint(target_e).owning_threads
        == pre_self_.get_endpoint(target_e).owning_threads);
    assert(post2_self_.get_endpoint(target_e).owning_threads
        == pre_self_.get_endpoint(target_e).owning_threads);
    assert(post1_self_.get_endpoint(target_e).owning_threads
        == post2_self_.get_endpoint(target_e).owning_threads);

    assert(post1_self_.get_endpoint(target_e).queue@
        == pre_self_.get_endpoint(target_e).queue@.push(thread_ptr));
    assert(post2_self_.get_endpoint(target_e).queue@
        == pre_self_.get_endpoint(target_e).queue@.push(thread_ptr));
    assert(post1_self_.get_endpoint(target_e).queue@
        =~= post2_self_.get_endpoint(target_e).queue@);

    // The unit return values are trivially equal.
    assert(r1 == r2);
}
